record_types.code:
type Batch_Query_Result (Success : Boolean := False) is record
   case Success is
      when True =>
         Reports : Mode_Report_Array;
         Count   : Positive;
      when False =>
         Error : Query_Error;
   end case;
end record;

type Mode_Query_Result (Success : Boolean := False) is record
   case Success is
      when True =>
         Report : Mode_Report;
      when False =>
         Error : Query_Error;
   end case;
end record;

